import scala.collection.mutable.ListBuffer

def solve(s: String, k: Long): String = {
  val buffer = ListBuffer[Char]()
  for (c <- s) {
    if (c.isLetter) {
      buffer += c
    } else if (c == '*') {
      if (buffer.nonEmpty) buffer.remove(buffer.length - 1)
    } else if (c == '#') {
      val copy = buffer.toList
      buffer ++= copy
    } else if (c == '%') {
      buffer.reverse
    }
  }
  if (k < 0 || k >= buffer.length) {
    "."
  } else {
    buffer(k).toString
  }
}
